  getCurrentList = async (email, fbName, shipAddy, bodyC, panelC, buttonC, letterC, panelLetterC, bothItems) => {
    try {
      await doc.useServiceAccountAuth({
        client_email: CLIENT_EMAIL,
        private_key: PRIVATE_KEY,
      });
      await doc.loadInfo();
      const sheet = doc.sheetsById[SHEET_ID];

      // await sheet2.loadCells("A1:O2004");
     await sheet.loadCells("A1:O20000");


      // var ss = SpreadsheetApp.getActiveSpreadsheet().getRange('NotShipped!A2:A2000');
 
      let allCyberValues = await sheet.getRows();
      let endOfCyber = allCyberValues.length;
      var today = new Date();
      var dd = String(today.getDate()).padStart(2, '0');
        var mm = String(today.getMonth() + 1).padStart(2, '0'); //January is 0!
        var yyyy = today.getFullYear();

        today = mm + '/' + dd + '/' + yyyy;
        let buildNamePaint = ""
        if(!bothItems){
        if(letterC.includes("white") && panelLetterC.includes("white") ){
            buildNamePaint = fbName + ' - WHITE LETTERING '
        }else if(letterC.includes("black") && panelLetterC.includes("black")){
            buildNamePaint = fbName + ' - BLACK LETTERING '
        }else if(letterC.includes("red") && panelLetterC.includes("red")){
            buildNamePaint = fbName + ' - RED LETTERING '
        }else if(letterC.includes("blue") && panelLetterC.includes("blue")){
            buildNamePaint = fbName + ' - BLUE LETTERING '

        }else if(letterC.includes("yellow") && panelLetterC.includes("yellow")){
            buildNamePaint = fbName + ' - YELLOW LETTERING '
        }else if(letterC.includes("green") && panelLetterC.includes("green")){
            buildNamePaint = fbName + ' - GREEN LETTERING '
        }else if(letterC.includes("custom") && panelLetterC.includes("custom")){
            buildNamePaint = fbName + ' - CUSTOM LETTERING '
        }else buildNamePaint = fbName + " - " + letterC + " - " + panelLetterC
      }else buildNamePaint = fbName
    sheet.getCell(endOfCyber + 1, 0).value = email;
    sheet.getCell(endOfCyber + 1, 1).value = buildNamePaint;
    sheet.getCell(endOfCyber + 1, 2).value = shipAddy;
    sheet.getCell(endOfCyber + 1, 3).value = bodyC;
    sheet.getCell(endOfCyber + 1, 4).value = panelC;
    sheet.getCell(endOfCyber + 1, 5).value = buttonC;
      await sheet.saveUpdatedCells();
      if(this.state.dropChoice === 'bonsai'){
        this.setState({showShop:  <BosnaiCard topTxt={'Bonsai'} urlPrice={'184'} pageShown={this.state.dropChoice} ></BosnaiCard> });

      }else if(this.state.dropChoice === 'sequoia'){
        this.setState({showShop:  <BosnaiCard topTxt={'Sequoia'} urlPrice={'184'} pageShown={this.state.dropChoice} ></BosnaiCard> });
    }else if(this.state.dropChoice === 'bonsai_sequoia'){
      this.setState({showShop:  <BosnaiCard topTxt={'Sequoia & Bonsai'} urlPrice={'359'} pageShown={this.state.dropChoice} ></BosnaiCard> });
    }
   
      // this.setState({ showShop: <BosnaiCard></BosnaiCard>});
    } catch (e) {
      console.error("Error: ", e);
    }
  };

