const ToDo = (props) => (<div className='singleToDo'>
<button onClick={()=>{
     props.delete(props.id)
   }}>&times;</button>
 <span className={props.completed ? 'completed' : ''}>{props.text}</span>

 <span id="minusQ"
 onClick={()=>{
   props.decrement(props.id)
 }}>-</span>
 <span className='cartQuant'>{props.quantity}</span>
 <span id="plusQ"
 onClick={()=>{
   props.increment(props.id)
 }}>+</span>
  
</div>)
