
import React from "react";
// import Don from "./Donut";
import test from "../cpine-png.png";
const USA_URL = process.env.REACT_APP_USA_URL;
const INTERN_URL = process.env.REACT_APP_INTERN_URL;
// let newDon = new Don();
// let Donut = newDon.getDon();
class ShopCard extends React.Component {
  state = {
    toggle: 'USA',
    color: '#e950b6',
    txt: 'USA',
    showModal: false,
    url: USA_URL,
    urlPrice: "258"
  };
  
  changeColor(txt, url, urlPrice) { 
    this.setState({
      url,
      txt,
      urlPrice
    })
  }
  
  handleClick = (e) => {
    const changeToggle = e.target.id === 'USA' ? 'Non-USA' : 'USA';
    const changeUrl = changeToggle === 'USA'  ? INTERN_URL  : USA_URL
    const changePrice = changeToggle === 'USA'  ? '300'  : '258'
    // const color = changeToggle === 'USA' ? '#3c2c31' : '#e950b6';
    const txt = changeToggle === 'USA' ? 'Non-USA' : 'USA';
    this.changeColor(txt, changeUrl, changePrice);
    this.setState({
      toggle: changeToggle,
    })
  }

  thxMessage = () =>{
    this.setState({showModal: true});
    setTimeout(() =>{
      this.setState({showModal: false});
    }, 3000);
  }
  render() {

    return (
      <div className="card"> 
        <h1>Sequoia {this.state.txt}</h1>
        <div className="img"><img src={test} alt="cherrypine sequoia mod"></img></div>
        <div className="shadow"></div>
        <div className="colors">
          <div id="USA" className="taste" onClick={this.handleClick}>
            <div className="color pink"></div>USA</div>
          <div id="Outside Of USA" className="taste" onClick={this.handleClick}>
            <div className="color brown"></div>Non-USA</div>
        </div>
        
        <div className="price">${this.state.urlPrice}.<sup>00</sup></div>
        <button onClick={() => { window.location.assign(this.state.url); }}>Purchase</button>
      </div>
    )
  }
}

export default ShopCard;