var stringSimilarity = require("string-similarity");

module.exports = function () {

    function bestNameMatch(string1, Players) {
        let bestMatch = [
            {
              match: null,
              name: null,
              firstName: null,
              lastName: null,
            },
          ];
              for (var a = 0; a < Players.length; a++) {
                  let matchName = stringSimilarity.compareTwoStrings(
                    string1,
                    Players[a].name
                  );    
                  bestMatch.push({
                    match: matchName,
                    printStatus: Players[a].printStatus,
                    name: Players[a].name,
                    paid: Players[a].paid,
                    address: Players[a].address,
                    body: Players[a].body,
                    panel: Players[a].panel,
                    button: Players[a].button,
                    paint: Players[a].paint,
                    pPricePaid: Players[a].pPricePaid,
                    shipNum: Players[a].shipNum,
                    email: Players[a].email,
                    orderNum: Players[a].orderNum,
                    rowLocation: Players[a].rowLocation
                  });
              }
          bestMatch.sort(function (a, b) {
            return b.match - a.match;
          });

          // console.log(bestMatch[0]);
 
          return [bestMatch[0], bestMatch[1], bestMatch[2], bestMatch[3], bestMatch[4], bestMatch[5]];

    }

    return {
        bestNameMatch: bestNameMatch,
      }
}