import React from "react";
import ReactDOM from "react-dom";
const blueimg = 'https://i.imgur.com/c1BOgpi.png';
const yellowimg = 'https://i.imgur.com/WscoySZ.png';
const pinkimg = 'https://i.imgur.com/QUEuz6J.png';
const smokedimg = 'https://i.imgur.com/uYn9J9c.png';
const clearimg = 'https://i.imgur.com/BMFHELY.png';
class AddToDo extends React.Component {
    constructor(props) {
      super(props)
      this.state = {
        value:'Smoked',
        butt:  <button>Add</button>
      }
      this.sendUp = this.sendUp.bind(this)
    }
    sendUp(value){
      this.props.add(value)
      this.setState({value:value})
    }
    handChange = (event) => {
      this.setState({value:event.target.value})
      this.setState({butt:<button onClick={(event)=>{
        this.sendUp(this.state.value)
      }}>Add</button>})
      let ele = document.getElementById("tankimage");
      if(event.target.value === "Blue"){
        ReactDOM.findDOMNode(ele).src = blueimg;
      }else if(event.target.value === "Smoked"){
        ReactDOM.findDOMNode(ele).src = smokedimg;
      }else if(event.target.value === "Clear"){
        ReactDOM.findDOMNode(ele).src = clearimg;
      }else if(event.target.value === "Pink"){
        ReactDOM.findDOMNode(ele).src = pinkimg;
      }else if(event.target.value === "Yellow"){
        ReactDOM.findDOMNode(ele).src = yellowimg;
      } 
    }
 
    render() {
      return <div className="insertToDos">
<label for="tanks" id="tanksLabel">Choose a Color:</label>
            <select id="tanks" name="tanks"  onChange={(event)=>{this.handChange(event)}}>
            <option id="noOp" value='none'>Choose Color...</option>

                <option id="smokedOp" value='Smoked'>Smoked Black</option>
                <option id="clearOp" value='Clear'>Clear</option>
                <option id="pinkOp" value='Pink'>Fuchsia</option>
                <option id="blueOp" value='Blue'>Electric Blue</option>
                <option id="yellowOp" value='Yellow'>Ultem Yellow</option>
            </select>
            {this.state.butt}
    
      </div>
    }
  }
  
  export default AddToDo;