import React from "react";
import "../Styles/App.css";
import ReactDOM from "react-dom";
import { GoogleSpreadsheet } from "google-spreadsheet";
import g from "./g-sheets.json";
import forest from "../forest.png";
import ReactGA from "react-ga";
import {Helmet} from "react-helmet";
const trackPage = (page) => {
    ReactGA.set({ page: page });
    ReactGA.set({
      page,
    });
    ReactGA.pageview(page);
  };
const SPREADSHEET_ID = process.env.REACT_APP_NEW_SHEET_ID;
const SHEET_ID = process.env.REACT_APP_HELP;
const CLIENT_EMAIL = process.env.REACT_APP_NEW_CLIENT_EMAIL;
const PRIVATE_KEY = g.private_key;
const doc = new GoogleSpreadsheet(SPREADSHEET_ID);

class HelpDesk extends React.Component {
  constructor(props) {
    super(props);

    this.state = {
      showShop: <h1 id="invalid">Welcome To The Help Desk</h1>,
      icon: "fa fa-eye",
      type: "text",
      email: props.email,
      gSheetIndex: props.gSheetIndex,
      whiteLeft: props.white,
      blackLeft: props.black,
      yellowLeft: props.yellow,
      name: "",
      message: "",
      optionsLeft: <>
                
      </>
      // showShop: <ShopCard></ShopCard>
    };
  }
  changeType = () => {
    const { type } = this.state;
    if (type === "password") {
      this.setState({
        icon: "fa fa-eye-slash",
        type: "text",
      });
    } else {
      this.setState({
        icon: "fa fa-eye",
        type: "text",
      });
    }
  };
  onSubmit = (e) => {
    this.setState({ showShop: <h1 id="invalid">Submitting....</h1>});
    let ele = document.getElementById("showShop");
    ReactDOM.findDOMNode(ele).style.display = "unset";
    let ele2 = document.getElementById("form");
    ReactDOM.findDOMNode(ele2).style.display = "none";

    this.getCurrentList(e.target[0].value, e.target[1].value)
    e.preventDefault();
  };
  getCurrentList = async (fbName, shipAddy) => {
    try {
      await doc.useServiceAccountAuth({
        client_email: CLIENT_EMAIL,
        private_key: PRIVATE_KEY,
      });
      await doc.loadInfo();
      const sheet = doc.sheetsById[SHEET_ID];

      // await sheet2.loadCells("A1:O2004");
      await sheet.loadCells("A1:O20000");


      // var ss = SpreadsheetApp.getActiveSpreadsheet().getRange('NotShipped!A2:A2000');
 
      let allCyberValues = await sheet.getRows();
      let endOfCyber = allCyberValues.length;
      var today = new Date();
      var dd = String(today.getDate()).padStart(2, '0');
        var mm = String(today.getMonth() + 1).padStart(2, '0'); //January is 0!
        var yyyy = today.getFullYear();

        today = mm + '/' + dd + '/' + yyyy;
    sheet.getCell(endOfCyber + 1, 0).value = today;
    sheet.getCell(endOfCyber + 1, 1).value = fbName;
    sheet.getCell(endOfCyber + 1, 2).value = shipAddy;
      await sheet.saveUpdatedCells();


      this.setState({ showShop: <> <h1 id="invalid">Your Ticket Has Been Submitted</h1>
      <div id="aroundHelp">
      <a className='button2' href="/#/help">Get Help</a>
    </div>
    </>});

    } catch (e) {
      console.error("Error: ", e);
    }
  };

  componentDidMount() {
    // let newLoc = window.location.hash.toString().replace("#/result/", "");
    // console.log(newLoc)
    //    let newLoc = prompt("enter pw");
    //     this.getCurrentList(newLoc)
    window.gapi.load("client", this.initClient);
    const page = window.location.hash.replace("#", "");
    trackPage(page);
  }
  render() {
    return (
      <div id="everything" className="formEverything1">
          <Helmet>
                <meta charSet="utf-8" />
                <title>Help Desk</title>
            </Helmet>
        <div id="showShop">
          <div id="topInfo"></div>
          
        </div>
        {this.state.showShop}
        
        <div id="aroundForm">
        
          <form
            className="form waitlistForm1"
            id="form"
            onSubmit={this.onSubmit}
          >
        <br></br>
        <h3 id="colorImageInfo">Please feel free to put anything here. Questions / comments / concerns / suggestions / feedback / requests are all welcome. I will respond to your ticket in facebook messanger as soon as possible.</h3>
            <div className="container">
              <input
                className="input"
                placeholder="Facebook Name"
                spellCheck={false}
                id="fbName"
                type={this.state.type}
                required
              />
              <br></br>
              <br></br>
              <br></br>
               <textarea
                className="input"
                placeholder="Any Information"
                spellCheck={false}
                id="shipAddy"
                rows="35"
                cols="40"
                type={this.state.type}
                required
              />
              <br></br>
              <div className="left-gradient" />
              <div className="sup-gradient" />
              <div className="right-gradient" />
              <div className="inf-gradient" />
              <div className="dumb-space" />
              <button className="button" id="waitlistButton1">
              Submit
            </button>
            </div>
           
          </form>
        </div>
        <div id="foot">
          <img src={forest} alt="forrest footer" />
        </div>
      </div>
    );
  }
}

export default HelpDesk;
