import React from "react";
class Display extends React.Component {

    
    // Displaying Components, but instead of Array.map, we use a for loop 
    
    render() { 
      var items = [];
        for (var i = 0; i < this.props.leng; i++) {
          items.push(<div className='flex-item' key={i}>
              <li>name: {this.props.items[i].name}</li>
              <li>address: {this.props.items[i].address}</li>
              <li>body: {this.props.items[i].body}</li>
              <li>button: {this.props.items[i].button}</li>
              <li>email: {this.props.items[i].email}</li>
              <li>orderNum: {this.props.items[i].orderNum}</li>
              <li>pPricePaid: {this.props.items[i].pPricePaid}</li>
              <li>paid: {this.props.items[i].paid}</li>
              <li>paint: {this.props.items[i].paint}</li>
              <li>panel: {this.props.items[i].panel}</li>
              <li>printStatus: {this.props.items[i].printStatus}</li>
              <li>rowLocation: {this.props.items[i].rowLocation}</li>
              <li>shipNum: {this.props.items[i].shipNum}</li>
          </div>);
        }    
        return (<div className="flex-container">{items}</div>);
        }
    
  };
  export default Display;

  











