
import React from "react";
// import Don from "./Donut";
const USA_URL_BONSAI = process.env.REACT_APP_BONSAI_URL_USA;
const INTERN_URL_BONSAI = process.env.REACT_APP_BONSAI_URL_INTERN;

const USA_URL_SEQUOIA = process.env.REACT_APP_SEQUOIA_URL_USA;
const INTERN_URL_SEQUOIA= process.env.REACT_APP_SEQUOIA_URL_INTERN;

const USA_URL_BS = process.env.REACT_APP_BS_URL_USA;
const INTERN_URL_BS = process.env.REACT_APP_BS_URL_INTERN;
// let newDon = new Don();
// let Donut = newDon.getDon();
class BSCard extends React.Component {
    constructor(props) {
        super(props);
  this.state = {
    toggle: 'USA',
    topTxt: props.topTxt,
    color: '#e950b6',
    txt: 'USA',
    showModal: false,
    url: USA_URL_BONSAI,
    urlPrice: props.urlPrice,
    pageShown: props.pageShown
  };
}
  
  changeColor(txt, url, urlPrice) { 
    this.setState({
      url,
      txt,
      urlPrice
    })
  }
  
  handleClick = (e) => {

    const changeToggle = e.target.id === 'USA' ? 'Non-USA' : 'USA';
    const changeUrl = changeToggle === 'USA'  ? INTERN_URL_BONSAI   : USA_URL_BONSAI 
    const changePrice = changeToggle === 'USA'  ? '215'  : '184'

    const changeUrl1 = changeToggle === 'USA'  ? INTERN_URL_SEQUOIA  : USA_URL_SEQUOIA
    const changePrice1 = changeToggle === 'USA'  ? '215'  : '184'


    const changeUrl2 = changeToggle === 'USA'  ? INTERN_URL_BS   : USA_URL_BS
    const changePrice2 = changeToggle === 'USA'  ? '390'  : '359'
    const txt = changeToggle === 'USA' ? 'Non-USA' : 'USA';
    this.setState({
        toggle: changeToggle,
      })
    if(this.state.pageShown === 'bonsai'){
        this.changeColor(txt, changeUrl, changePrice);
    }else if(this.state.pageShown === 'sequoia'){
        this.changeColor(txt, changeUrl1, changePrice1);
    }else if(this.state.pageShown === 'bonsai_sequoia'){
        this.changeColor(txt, changeUrl2, changePrice2);
    }

 
   
 
  }

  thxMesge = () =>{
    this.setState({showModal: true});
    setTimeout(() =>{
      this.setState({showModal: false});
    }, 3000);
  }


  componentDidMount() {
    if(this.state.pageShown === 'bonsai'){
        this.setState({topTxt: 'Bonsai'})
    }else if(this.state.pageShown === 'sequoia'){
        this.setState({topTxt: 'Sequoia'})
        this.setState({url: USA_URL_SEQUOIA})
    }else if(this.state.pageShown === 'bonsai_sequoia'){
        this.setState({urlPrice: '359'})
        this.setState({topTxt: 'Bonsai & Sequoia'})
        this.setState({url: USA_URL_BS})
    } 
  }
//   componentDidUpdate() {
//     if(this.state.pageShown === 'bonsai'){
//         this.setState({topTxt: 'Bonsai'})
//     }else if(this.state.pageShown === 'sequoia'){
//         this.setState({topTxt: 'Sequoia'})
//         this.setState({url: USA_URL_SEQUOIA})
//     }else if(this.state.pageShown === 'bonsai_sequoia'){
//         this.setState({urlPrice: '359'})
//         this.setState({topTxt: 'Bonsai & Sequoia'})
//         this.setState({url: USA_URL_BS})
//     } 
//   }
  render() {

    return (
      <div className="card"> 
        <h1>{this.state.topTxt} {this.state.txt}</h1>
        <div className="img"><img src="https://i.imgur.com/RNWOu0K.png" alt="cherrypine bonsai mod"></img></div>
        <div className="shadow"></div>
        <div className="colors">
          <div id="USA" className="taste" onClick={this.handleClick}>
            <div className="color pink"></div>USA</div>
          <div id="Non-USA" className="taste" onClick={this.handleClick}>
            <div className="color brown"></div>Non-USA</div>
        </div>
        
        <div className="price">${this.state.urlPrice}.<sup>00</sup></div>
        <button onClick={() => { window.location.assign(this.state.url); }}>Purchase</button>
      </div>
    )
  }
}

export default BSCard;