import React from "react";
import "../Styles/App.css";
import ShopCard from "./Voltrove";
import ReactDOM from "react-dom";
import { GoogleSpreadsheet } from "google-spreadsheet";
import g from "./g-sheets.json";
import forest from "../forest.png";
const SPREADSHEET_ID = process.env.REACT_APP_NEW_SHEET_ID;
const SHEET_ID = process.env.REACT_APP_OPEN_DROP;
const CLIENT_EMAIL = process.env.REACT_APP_NEW_CLIENT_EMAIL;
const PRIVATE_KEY = g.private_key;
const doc = new GoogleSpreadsheet(SPREADSHEET_ID);
class VoltroveMain extends React.Component {
  constructor(props) {
    super(props);

    this.state = {
      showShop: <h1 id="invalid">Welcome</h1>,
      icon: "fa fa-eye",
      type: "text"
    };
  }
  changeType = () => {
    const { type } = this.state;
    if (type === "password") {
      this.setState({
        icon: "fa fa-eye-slash",
        type: "text",
      });
    } else {
      this.setState({
        icon: "fa fa-eye",
        type: "text",
      });
    }
  };
  onSubmit = (e) => {
    let ele = document.getElementById("showShop");
    ReactDOM.findDOMNode(ele).style.display = "unset";
    let ele2 = document.getElementById("form");
    ReactDOM.findDOMNode(ele2).style.display = "none";


    let ele24 = document.getElementById("aroundImage");
    ReactDOM.findDOMNode(ele24).style.display = "none";



    let ele26 = document.getElementById("aroundForm");
    ReactDOM.findDOMNode(ele26).style.display = "none";

    this.getCurrentList(e.target[0].value, e.target[2].value, document.querySelector('input[name="body_color"]:checked').value, e.target[1].value);
    e.preventDefault();
  };
  getCurrentList = async (fbName, shipAddy, bodyC, email) => {
    try {
      await doc.useServiceAccountAuth({
        client_email: CLIENT_EMAIL,
        private_key: PRIVATE_KEY,
      });
      await doc.loadInfo();
      const sheet = doc.sheetsById[SHEET_ID];
      await sheet.loadCells("A1:AA30000");
      let allCyberValues = await sheet.getRows();
      let endOfCyber = allCyberValues.length;

      sheet.getCell(endOfCyber + 1, 0).value = email;
      sheet.getCell(endOfCyber + 1, 1).value = fbName;
      sheet.getCell(endOfCyber + 1, 3).value = bodyC;
      sheet.getCell(endOfCyber + 1, 4).value = bodyC;
      sheet.getCell(endOfCyber + 1, 5).value = "batch color BUTTON";
      sheet.getCell(endOfCyber + 1, 2).value = shipAddy;
      await sheet.saveUpdatedCells();
      this.setState({ showShop: <ShopCard></ShopCard> });

    } catch (e) {
      console.error("Error: ", e);
    }
  };


  render() {
    return (
      <div id="everything" className="formEverything">
        <div id="showShop">
          <div id="topInfo"></div>
          
        </div>
        {this.state.showShop}
        
        <div id="aroundForm">
        
          <form
            className="form waitlistForm"
            id="form"
            onSubmit={this.onSubmit}
          >
              <h1 id="orderTitle">The Oak Drop</h1>
        <div id="aroundImage">
        <img
          id="colorOptionsImage"
          src="https://i.imgur.com/j47Jm8h.jpeg"
          alt="https://i.imgur.com/j47Jm8h.jpeg"
        />

        </div>
        <br></br>

            <div className="container">
              <input
                className="input"
                placeholder="Facebook Name"
                spellCheck={false}
                id="fbName"
                type={this.state.type}
                required
              />
              <br></br>
              <br></br>
              <br></br>
              <input
            className="input"
            placeholder="Email Address"
            spellCheck={false}
            id="email"
            type={this.state.type}
            required
          />
           <br></br>
          <br></br>
          <br></br>
               <input
                className="input"
                placeholder="Shipping Address"
                spellCheck={false}
                id="shipAddy"
                type={this.state.type}
                required
              />
              <br></br>
              <div id="colorInputs">
                <h3>Mod Edition</h3>
                <input
                  type="radio"
                  id="white_body"
                  name="body_color"
                  value="With Logo's"
                  required
                />
                <label for="white_body">With Voltrove Logo's</label>
                <br></br>
                <input
                  type="radio"
                  id="black_body"
                  name="body_color"
                  value="Without Logo's"
                />
                <label for="black_body">Without Voltrove Logos</label>
                <br></br>
               
              <div className="left-gradient" />
              <div className="sup-gradient" />
              <div className="right-gradient" />
              <div className="inf-gradient" />
              <div className="dumb-space" />
            </div>
            </div>
            <button className="button" id="waitlistButton">
              Submit
            </button>
          </form>
        </div>
        <div id="foot">
          <img src={forest} alt="forrest footer" />
        </div>
      </div>
    );
  }
}

export default VoltroveMain;
