
import React from "react";
// import Don from "./Donut";
import test from "../cpine-png.png";
const USA_URL = process.env.REACT_APP_WHOLESALE_URL;
// let newDon = new Don();
// let Donut = newDon.getDon();
class ShopCard extends React.Component {
  state = {
    toggle: 'Wholesale',
    color: '#e950b6',
    txt: 'Wholesale',
    showModal: false,
    url: USA_URL,
    urlPrice: "200"
  };
  
  changeColor(txt, url, urlPrice) { 
    this.setState({
      url,
      txt,
      urlPrice
    })
  }
  

  thxMessage = () =>{
    this.setState({showModal: true});
    setTimeout(() =>{
      this.setState({showModal: false});
    }, 3000);
  }
  render() {

    return (
      <div className="card"> 
        <h1>Sequoia {this.state.txt}</h1>
        <div className="img"><img src={test} alt="cherrypine sequoia mod"></img></div>
        <div className="shadow"></div>
        <div className="colors">
          <div id="USA" className="taste" >
            <div className="color pink"></div>Wholesale</div>
        </div>
        
        <div className="price">${this.state.urlPrice}.<sup>00 ea. </sup></div>
        <button onClick={() => { window.location.assign(this.state.url); }}>Purchase</button>
        <div> <br></br> (Modify quantity on checkout page)</div>
      </div>
    )
  }
}

export default ShopCard;